/**
 * MMS - API Client Utilities
 *
 * Centralized API client for backend communication
 */

const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:4000';

interface ApiResponse<T> {
  data: T | null;
  error: string | null;
}

/**
 * Generic fetch wrapper with error handling
 */
export async function apiFetch<T>(endpoint: string, options?: RequestInit): Promise<ApiResponse<T>> {
  try {
    const response = await fetch(`${API_BASE_URL}${endpoint}`, {
      ...options,
      headers: {
        'Content-Type': 'application/json',
        ...options?.headers,
      },
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      return {
        data: null,
        error: errorData.error || `API Error: ${response.status}`,
      };
    }

    const data = await response.json();
    return { data, error: null };
  } catch (err) {
    return {
      data: null,
      error: err instanceof Error ? err.message : 'Network error',
    };
  }
}

/**
 * Dashboard API
 */
export interface DashboardSummary {
  totalTrains: number;
  availableTrains: number;
  inMaintenanceCount: number;
  kmVariance: number;
  varianceStatus: 'green' | 'yellow' | 'red';
}

export interface DepotCapacity {
  id: string;
  name: string;
  code: string;
  currentOccupancy: number;
  maxCapacity: number;
  percentUsed: number;
}

export interface DepotCapacityResponse {
  depots: DepotCapacity[];
}

export interface MaintenanceAlert {
  id: string;
  trainId: string;
  type: 'PM1' | 'PM2' | 'HM' | 'OVH';
  date: string;
  depot: string;
  depotCode: string;
  durationDays: number;
}

export interface MaintenanceAlertsResponse {
  totalUpcoming: number;
  countByType: {
    PM1: number;
    PM2: number;
    HM: number;
    OVH: number;
  };
  alerts: MaintenanceAlert[];
}

export const dashboardApi = {
  getSummary: () => apiFetch<DashboardSummary>('/api/dashboard/summary'),
  getDepotCapacity: () => apiFetch<DepotCapacityResponse>('/api/dashboard/depot-capacity'),
  getMaintenanceAlerts: () => apiFetch<MaintenanceAlertsResponse>('/api/dashboard/maintenance-alerts'),
};

/**
 * Trains API
 */
export interface Train {
  id: string;
  trainId: string;
  fleetId: string;
  baseDepotId: string;
  currentKm: number;
  targetKm: number;
  fitnessStatus: 'fit' | 'unfit';
  lastMaintenanceDate: string | null;
  nextMaintenanceKm: number | null;
  latitude: string | null;
  longitude: string | null;
  fleet: {
    id: string;
    name: string;
    manufacturer: string | null;
  } | null;
  baseDepot: {
    id: string;
    name: string;
    code: string;
    latitude: string | null;
    longitude: string | null;
  } | null;
  deltaFromAverage: number;
  deltaPercent: number;
}

export interface TrainsResponse {
  trains: Train[];
}

export interface Depot {
  id: string;
  name: string;
  code: string;
  latitude: string | null;
  longitude: string | null;
  capacityTracks: number;
  capacityManhours: number;
}

export interface DepotsResponse {
  depots: Depot[];
}

export const trainsApi = {
  getAll: (params?: { status?: string; depot?: string }) => {
    const query = new URLSearchParams();
    if (params?.status) query.set('status', params.status);
    if (params?.depot) query.set('depot', params.depot);
    const queryStr = query.toString();
    return apiFetch<TrainsResponse>(`/api/trains${queryStr ? `?${queryStr}` : ''}`);
  },
  getById: (id: string) => apiFetch<Train>(`/api/trains/${id}`),
};

export const depotsApi = {
  getAll: () => apiFetch<DepotsResponse>('/api/depots'),
};

/**
 * Services API
 */
export interface Service {
  id: string;
  serviceCode: string;
  origin: string;
  destination: string;
  distanceKm: number;
  departureTime: string;
  arrivalTime: string;
  serviceType: string;
}

export interface PendingServicesResponse {
  date: string;
  services: Service[];
}

export const servicesApi = {
  getPending: (date?: string) => {
    const query = date ? `?date=${date}` : '';
    return apiFetch<PendingServicesResponse>(`/api/services/pending${query}`);
  },
};

/**
 * Allocations API
 */
export interface Recommendation {
  trainId: string;
  train_id: string;
  score: number;
  justifications: string[];
  deadRunningKm: number;
}

export interface RecommendationsResponse {
  recommendations: Recommendation[];
  solverTimeMs: number;
  fallback?: boolean;
}

export interface Allocation {
  id: string;
  serviceId: string;
  trainId: string;
  allocationDate: string;
  status: string;
  score: number | null;
  justifications: string[] | null;
}

export interface AllocationResponse {
  allocation: Allocation;
}

export const allocationsApi = {
  recommend: (serviceId: string, date: string) =>
    apiFetch<RecommendationsResponse>('/api/allocations/recommend', {
      method: 'POST',
      body: JSON.stringify({ serviceId, date }),
    }),
  create: (serviceId: string, trainId: string, date: string, score?: number, justifications?: string[]) =>
    apiFetch<AllocationResponse>('/api/allocations', {
      method: 'POST',
      body: JSON.stringify({ serviceId, trainId, date, score, justifications }),
    }),
};

// Helper function for POST requests
async function apiFetchWithBody<T>(endpoint: string, options: RequestInit): Promise<ApiResponse<T>> {
  try {
    const response = await fetch(`${API_BASE_URL}${endpoint}`, {
      ...options,
      headers: {
        'Content-Type': 'application/json',
        ...options.headers,
      },
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      return {
        data: null,
        error: errorData.error || `API Error: ${response.status}`,
      };
    }

    const data = await response.json();
    return { data, error: null };
  } catch (err) {
    return {
      data: null,
      error: err instanceof Error ? err.message : 'Network error',
    };
  }
}

/**
 * MMS - Metro Mileage Management System
 * Database Schema using Drizzle ORM
 *
 * Based on Architecture Decision Document (2025-12-28)
 */

import {
  pgTable,
  uuid,
  varchar,
  integer,
  decimal,
  timestamp,
  date,
  time,
  jsonb,
  index,
  uniqueIndex,
} from 'drizzle-orm/pg-core';
import { relations } from 'drizzle-orm';

// =============================================================================
// Fleets Table
// =============================================================================
export const fleets = pgTable('fleets', {
  id: uuid('id').primaryKey().defaultRandom(),
  name: varchar('name', { length: 100 }).notNull(),
  manufacturer: varchar('manufacturer', { length: 50 }),
  pm1IntervalKm: integer('pm1_interval_km').notNull(),
  pm2IntervalKm: integer('pm2_interval_km').notNull(),
  hmIntervalKm: integer('hm_interval_km').notNull(),
  createdAt: timestamp('created_at').defaultNow(),
});

// =============================================================================
// Depots Table
// =============================================================================
export const depots = pgTable(
  'depots',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    name: varchar('name', { length: 100 }).notNull(),
    code: varchar('code', { length: 10 }).notNull(),
    latitude: decimal('latitude', { precision: 10, scale: 6 }),
    longitude: decimal('longitude', { precision: 10, scale: 6 }),
    capacityTracks: integer('capacity_tracks').default(5),
    capacityManhours: integer('capacity_manhours').default(80),
    createdAt: timestamp('created_at').defaultNow(),
  },
  (table) => [
    uniqueIndex('depots_code_idx').on(table.code),
  ]
);

// =============================================================================
// Trains Table
// =============================================================================
export const trains = pgTable(
  'trains',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    trainId: varchar('train_id', { length: 20 }).notNull(), // Business ID: UTE-3400-012
    fleetId: uuid('fleet_id').references(() => fleets.id),
    baseDepotId: uuid('base_depot_id').references(() => depots.id),
    currentKm: integer('current_km').default(0),
    targetKm: integer('target_km').default(0),
    fitnessStatus: varchar('fitness_status', { length: 10 }).default('fit'),
    lastMaintenanceDate: date('last_maintenance_date'),
    nextMaintenanceKm: integer('next_maintenance_km'),
    latitude: decimal('latitude', { precision: 10, scale: 6 }),
    longitude: decimal('longitude', { precision: 10, scale: 6 }),
    createdAt: timestamp('created_at').defaultNow(),
    updatedAt: timestamp('updated_at').defaultNow(),
  },
  (table) => [
    uniqueIndex('trains_train_id_idx').on(table.trainId),
    index('trains_fleet_idx').on(table.fleetId),
    index('trains_depot_idx').on(table.baseDepotId),
  ]
);

// =============================================================================
// Services Table
// =============================================================================
export const services = pgTable(
  'services',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    serviceCode: varchar('service_code', { length: 20 }).notNull(), // IC 501
    origin: varchar('origin', { length: 100 }).notNull(),
    destination: varchar('destination', { length: 100 }).notNull(),
    distanceKm: integer('distance_km').notNull(),
    departureTime: time('departure_time').notNull(),
    arrivalTime: time('arrival_time').notNull(),
    serviceType: varchar('service_type', { length: 20 }).default('regional'),
    createdAt: timestamp('created_at').defaultNow(),
  },
  (table) => [
    uniqueIndex('services_code_idx').on(table.serviceCode),
  ]
);

// =============================================================================
// Allocations Table
// =============================================================================
export const allocations = pgTable(
  'allocations',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    serviceId: uuid('service_id').references(() => services.id),
    trainId: uuid('train_id').references(() => trains.id),
    allocationDate: date('allocation_date').notNull(),
    status: varchar('status', { length: 20 }).default('pending'),
    score: integer('score'),
    justifications: jsonb('justifications').$type<string[]>(),
    createdBy: varchar('created_by', { length: 100 }),
    createdAt: timestamp('created_at').defaultNow(),
  },
  (table) => [
    uniqueIndex('allocations_service_date_idx').on(table.serviceId, table.allocationDate),
    index('allocations_date_idx').on(table.allocationDate),
    index('allocations_status_idx').on(table.status),
  ]
);

// =============================================================================
// Mileage History Table
// =============================================================================
export const mileageHistory = pgTable(
  'mileage_history',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    trainId: uuid('train_id').references(() => trains.id),
    recordedDate: date('recorded_date').notNull(),
    kmValue: integer('km_value').notNull(),
    createdAt: timestamp('created_at').defaultNow(),
  },
  (table) => [
    index('mileage_train_date_idx').on(table.trainId, table.recordedDate),
  ]
);

// =============================================================================
// Maintenance Schedules Table
// =============================================================================
export const maintenanceSchedules = pgTable(
  'maintenance_schedules',
  {
    id: uuid('id').primaryKey().defaultRandom(),

